#' multicheck
#' @title multicheck
#' @description Perform various statistical checks on numeric variables against a grouping factor.
#' @param df A data frame composed entirely of numeric variables.
#' @param y A factor used as the grouping variable.
#' @param alpha Significance level (default: 0.05).
#' @importFrom foreach foreach %dopar% %:%
#' @return A named list of p-values, ratios, and decision flags for each variable.
#' @export
#' @examples
#' csv <- system.file("tests/csv/Vars.csv", package = "trident")
#'
#' df <- read.csv(file = csv, header = TRUE, as.is = TRUE, row.names = NULL)
#'
#' fa <- as.factor(c(rep("A", 15), rep("B", 15), rep("C", 15)))
#'
#' df[] <- lapply(df, as.numeric)
#'
#' DFstat <- multicheck(df = df, y = fa, alpha = 0.05)
#'
#' csv <- system.file("tests/csv/DFstat.csv", package = "trident")
#'
#' write.csv(DFstat, file = csv, row.names = FALSE, quote = FALSE)
#'

multicheck <- function(df, y, alpha = 0.05) {

  # --- Input validation -------------------------------------------------------
  if (!is.data.frame(df)) {
    stop("'df' must be an object of class data.frame (see ?is.data.frame).")
  }
  if (!is.factor(y)) {
    stop("'y' must be a factor.")
  }
  if (any(!apply(df, 2, is.numeric))) {
    stop("All columns of 'df' must be numeric.")
  }

  # --- Data preparation -------------------------------------------------------
  mydf <- data.frame(y = as.factor(y), df)
  mydf <- mydf[is.finite(rowSums(mydf[, -1])), ] # Retain only rows with finite values in numeric columns

  my_matrix <- t(matrix(
                        data  = unlist(mydf[, -1]),
                        ncol  = ncol(df)
                       )
                 )
  
  my_factor <- mydf[, 1]
  n_vars    <- nrow(my_matrix)
  var_names <- colnames(df)

  # --- Parallel backend setup -------------------------------------------------
  cl <- snow::makeSOCKcluster(max(1L, parallel::detectCores() - 1L)) # Leave at least one core free
  
  doSNOW::registerDoSNOW(cl)
  
  on.exit(snow::stopCluster(cl), add = TRUE)  # Ensure cluster is stopped when function exits, even if an error occurs

  # --- Statistical tests ------------------------------------------------------

  # Welch ANOVA, with error handling to return NA for any variable that causes an error (e.g., due to insufficient data)
  # Robust to non-normality and heteroscedasticity, but less powerful than OneWay Anova when assumptions are met.
  p_anova.W <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    result <- tryCatch(
      stats::oneway.test(
        my_matrix[i, ] ~ my_factor,
        na.action = "na.omit"
      )$p.value,
      error = function(e) NA_real_
    )
    if (!is.numeric(result) || length(result) != 1L) NA_real_ else result
  }

  # Kruskal-Wallis test (robust to non-normality)
  p_kruskal <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    stats::kruskal.test(my_matrix[i, ] ~ my_factor)$p.value
  }

  # ANOVA residuals (for normality and homoscedasticity tests)
  residuals_list <- foreach::foreach(
    i = seq(2L, ncol(mydf))
  ) %dopar% {
    stats::aov(mydf[, i] ~ mydf[, 1])$residuals
  }
  residuals_mat <- t(matrix(
    data = unlist(residuals_list),
    ncol = n_vars
  ))

  # Anderson-Darling test; not used for decision tree
  p_anderson <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    nortest::ad.test(residuals_mat[i, ])$p.value
  }

  # Bartlett test; only used if normality is TRUE in the decision tree
  p_bartlett <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    stats::bartlett.test(residuals_mat[i, ] ~ my_factor)$p.value
  }

  # Levene test; only used if normality is nearly in the decision tree
  p_levene <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    car::leveneTest(residuals_mat[i, ], my_factor, center = "median")$`Pr(>F)`[1]
  }

  # Shapiro-Wilk test; only used for normality assessment in the decision tree
  p_shapiro <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    stats::shapiro.test(residuals_mat[i, ])$p.value
  }

  # Asymmetry Ratio (bootstrap BCA)
  # The authors of DescTools (Andri Signorell) explicitly chose bootstrap as the default/recommended approach
  # for the confidence interval of Skew() and Kurt()
  skw_ratio <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {

  withr::with_seed(12, { # to ensure reproducibility of the bootstrap results, which can vary across runs due to random resampling. Setting a seed allows for consistent results when the function is run multiple times.
    skw <- DescTools::Skew(
      x          = residuals_mat[i, ],
      method     = 3,
      conf.level = 0.95,
      ci.type    = "bca",
      R          = 1000
    )
    result <- abs(skw[[1]] / (skw[[3]] - skw[[2]]))
  })
  }

  # Inter-group ratio variances
  variance_per_cat <- foreach::foreach(
    j        = seq_along(levels(my_factor)),
    .combine = "cbind"
  ) %:%
    foreach::foreach(
      i        = seq_len(n_vars),
      .combine = "c"
    ) %dopar% {
      stats::var(residuals_mat[i, which(my_factor == levels(my_factor)[j])])
    }

  var_ratio <- foreach::foreach(
    i        = seq_len(n_vars),
    .combine = "c"
  ) %dopar% {
    mins <- min(variance_per_cat[i, ])
    if (mins != 0) {
      max(variance_per_cat[i, ]) / mins
    } else {
      NA_real_
    }
  }

  # --- decision tree ------------------------------------------------------

  is_normal        <- character(n_vars)
  is_homoscedastic <- character(n_vars)
  is_discriminant  <- character(n_vars)

  # Normalité (via Shapiro-Wilk et ratio d'asymétrie)
  is_normal[p_shapiro >  alpha]                   <- "TRUE"
  is_normal[p_shapiro <= alpha & skw_ratio <  2]  <- "nearly"
  is_normal[p_shapiro <= alpha & skw_ratio >= 2]  <- "FALSE"

  # Heteroscedsasticity is set FALSE if normality is FALSE
  is_homoscedastic[is_normal == "FALSE"] <- "FALSE"

  # Homoscédasticité Bartlett
  is_homoscedastic[is_normal == "TRUE"    & p_bartlett >  alpha] <- "TRUE"
  is_homoscedastic[is_normal == "TRUE"    & p_bartlett <= alpha & var_ratio <= 3] <- "nearly"
  is_homoscedastic[is_normal == "TRUE"    & p_bartlett <= alpha & var_ratio >  3] <- "FALSE"

  # Homoscedasticity Levene
  is_homoscedastic[is_normal == "nearly"  & p_levene   >  alpha] <- "TRUE"
  is_homoscedastic[is_normal == "nearly"  & p_levene   <= alpha] <- "FALSE"


  # Discrimination ability
  is_discriminant[] <- "FALSE"
  
  homo_ok <- is_homoscedastic %in% c("TRUE", "nearly")

  is_discriminant[homo_ok & p_anova.W < alpha] <- "TRUE"

  # --- Results --------------------------------------------------------------
  list(
    variable         = var_names,
    anderson_p.value = p_anderson, # not used
    anova_p.value    = p_anova.W,
    bartlett_p.value = p_bartlett,
    kruskal_p.value  = p_kruskal,  # not used
    levene_p.value   = p_levene,
    shapiro_p.value  = p_shapiro,
    skewness.ratio   = skw_ratio,
    variance.ratio   = var_ratio,
    is.normal        = is_normal,
    is.homoscedastic = is_homoscedastic,
    is.discriminant  = is_discriminant
  )
}

# run_posthoc
#' @title run_posthoc
#' @description Ranks the top 3 variables capable of discriminating categories for each pair of factor levels.
#' @param x Numeric vector of observations.
#' @param y Factor grouping variable.
#' @param method Character. Post-hoc method (e.g. "hsd", "lsd").
#' @param alpha Numeric. Significance threshold.
#'
#' @return Numeric vector containing: p-values, mean significant p-value, geometric mean,
#'         number of significant tests.
#' @export
#' @examples
#' data("iris")
#'
#' res <- run_posthoc( x = iris$Sepal.Length,
#'                     y = iris$Species,
#'                     method = "hsd",
#'                     alpha = 0.05)
#'
#' cat("p_vals: ",    res[1:3], "\n")
#' cat("avg_p:  ",    res[4], "\n")
#' cat("geo_p:  ",    res[5], "\n")
#' cat("n_signif:  ", res[6], "\n")
 run_posthoc <- function(x, y, method, alpha) {
      
    ph     <- DescTools::PostHocTest(
                stats::aov(x ~ y),
                method = method,
                conf.level = 1 - alpha)
    
    p_vals <- as.numeric(ph[[1]][, "pval"])
    
    signif_p <- p_vals[p_vals < alpha]
    
    # Calculate metrics
    avg_p    <- if(length(signif_p) > 0) mean(signif_p) else 1
    geo_p    <- if(length(signif_p) > 0) exp(mean(log(signif_p))) else 1
    n_signif <- length(signif_p)
    
    return(c(p_vals, avg_p, geo_p, n_signif))
    
  }

